import pandas as pd
from xbbg import blp
def nat(o): return o.to_native() if hasattr(o,"to_native") else o

def earliest(tickers, flds, start="1980-01-01"):
    try:
        r=nat(blp.bdh(tickers=tickers, flds=flds, start_date=start, end_date="2026-06-02", Per="Y", Fill="P"))
        if r is None or len(r)==0: return {}
        r=r.dropna(subset=["value"])
        out={}
        for (tk,fl),g in r.groupby(["ticker","field"]):
            out[(tk,fl)]=pd.to_datetime(g["date"]).min().strftime("%Y-%m-%d")
        return out
    except Exception as e:
        return {"ERR":str(e)[:80]}

print("=== OHLCV (PX_LAST) earliest, old names ===")
for k,v in earliest(["IBM US Equity","GE US Equity","XOM US Equity","KO US Equity","JPM US Equity","AAPL US Equity","MSFT US Equity","SPX Index"], ["PX_LAST"], "1960-01-01").items():
    print("  ",k,"->",v)

print("=== Vol fields earliest (AAPL, MSFT, IBM) ===")
for k,v in earliest(["AAPL US Equity","MSFT US Equity","IBM US Equity"], ["VOLATILITY_30D","HIST_PUT_IMP_VOL","VOLATILITY_260D"]).items():
    print("  ",k,"->",v)

print("=== Liquidity fields earliest (AAPL, IBM) ===")
for k,v in earliest(["AAPL US Equity","IBM US Equity"], ["VOLUME_AVG_30D","TURNOVER","EQY_SH_OUT","EQY_FLOAT"]).items():
    print("  ",k,"->",v)

print("=== Short interest earliest (AAPL, IBM, GE) ===")
for k,v in earliest(["AAPL US Equity","IBM US Equity","GE US Equity"], ["SHORT_INT","SI_PERCENT_EQUITY_FLOAT"]).items():
    print("  ",k,"->",v)

print("=== Index/vol-context series earliest ===")
idx=["UX1 Index","UX2 Index","UX7 Index","SKEW Index","VVIX Index","VIX9D Index","VXN Index","RVX Index","VXEEM Index","OVX Index","GVZ Index","COR1M Index","COR3M Index","COR6M Index","MOVE Index","CVIX Index","JPMVXYG7 Index","VIX Index"]
for k,v in earliest(idx, ["PX_LAST"], "1985-01-01").items():
    print("  ",k,"->",v)
